// schemas/expense.ts
import { z } from 'zod';

export const ExpenseSchema = z.object({
  amount: z.number().min(0.01).max(99999.99),
  description: z.string().min(1).max(200),
  categoryId: z.string().min(1),
  date: z.string().refine(d => new Date(d) <= new Date(), 'Date cannot be in the future'),
  paymentMethod: z.enum(['Cash', 'Debit Card', 'Credit Card', 'UPI/Other']),
  note: z.string().max(100).optional(),
});

// db.ts
import Dexie, { type Table } from 'dexie';
import type { Expense, Category, Budget, UserSettings } from '@/types';

export class CashPulseDB extends Dexie {
  expenses!: Table<Expense>;
  categories!: Table<Category>;
  budgets!: Table<Budget>;
  settings!: Table<UserSettings>;

  constructor() {
    super('cashpulse');
    this.version(1).stores({
      expenses: '++id, date, categoryId, amount, createdAt',
      categories: '++id, name, isDefault',
      budgets: '++id, month',
      settings: '++id',
    });
  }
}

export const db = new CashPulseDB();

// hooks/useToast.ts
export function useToast() {
  const { toast } = useRadixToast();
  return {
    success: (title: string) => toast({ type: 'success', title, duration: 2000 }),
    error: (title: string, description?: string) => toast({ type: 'error', title, description, duration: 4000 }),
  };
}

// store/expenseSlice.ts
import { useLiveQuery } from 'dexie-react-hooks';
import { db } from '@/db';

export function useMonthExpenses(month: string) {
  return useLiveQuery(
    () => db.expenses.where('date').between(`${month}-01`, `${month}-31`).toArray(),
    [month]
  );
}

// lib/logger.ts
const LOG_LEVEL = import.meta.env.PROD ? 'warn' : 'debug';
const levels = { debug: 0, info: 1, warn: 2, error: 3 };

export const logger = {
  info: (module: string, msg: string, data?: unknown) => {
    if (levels[LOG_LEVEL] <= levels.info) console.log(JSON.stringify({ ts: Date.now(), level: 'info', module, msg, data }));
  },
  warn: (module: string, msg: string, data?: unknown) => console.warn(JSON.stringify({ ts: Date.now(), level: 'warn', module, msg, data })),
  error: (module: string, msg: string, data?: unknown) => console.error(JSON.stringify({ ts: Date.now(), level: 'error', module, msg, data })),
};

